/**
 * TEMPORARY verbose tracing for the Explain flow (OPIK-6425).
 *
 * Logs the full bidirectional bridge timeline from the HOST frame (top page),
 * so it is visible in the top-page DevTools console regardless of the
 * cross-origin Ollie iframe. The single most diagnostic signal lives here: it
 * disambiguates whether an `explain:error` arrives as an INBOUND event (the
 * console runner emitted it) or is generated by the HOST itself
 * (watchdog/timeout/pod-loss), and it reports the live `explain:run`
 * subscriber count (≥2 ⇒ a duplicate runner is subscribed).
 *
 * Remove this file (and its imports in explainStore.ts / assistantBridge.ts)
 * once the spurious-error root cause is confirmed. Grep `[EXPLAIN]` to find
 * every call site.
 */

// Flip to false to silence without ripping out the call sites.
export const EXPLAIN_DEBUG = true;

// Wall-clock stamp (HH:MM:SS.mmm) so host and iframe logs interleave correctly
// in DevTools — performance.now() has a per-frame time origin and would NOT
// line up across the host/iframe boundary.
const stamp = (): string => {
  const d = new Date();
  const p = (n: number, w = 2) => String(n).padStart(w, "0");
  return `${p(d.getHours())}:${p(d.getMinutes())}:${p(d.getSeconds())}.${p(
    d.getMilliseconds(),
    3,
  )}`;
};

/** First 5 chars of an explainId — enough to correlate, short enough to scan. */
export const shortId = (id: string | undefined): string =>
  id ? id.slice(0, 5) : "—";

export function explainLog(scope: string, msg: string, data?: unknown): void {
  if (!EXPLAIN_DEBUG) return;
  const prefix = `%c[EXPLAIN][host:${scope}]%c ${stamp()} ${msg}`;
  const tag = "color:#7c3aed;font-weight:bold";
  const rest = "color:inherit;font-weight:normal";
  if (data !== undefined) {
    // eslint-disable-next-line no-console
    console.log(prefix, tag, rest, data);
  } else {
    // eslint-disable-next-line no-console
    console.log(prefix, tag, rest);
  }
}
